# Expected data structure injected from previous steps:
# data = {'DAL': {'fuel_cost_pct': 0.24, 'hedge_coverage': 0.65}, 'LHA': {'fuel_cost_pct': 0.27, 'hedge_coverage': 0.45}}
# Using conservative industry averages if exact extraction varies

def calculate_margin_shrinkage(data, oil_shock=0.15):
    results = {}
    for ticker, metrics in data.items():
        fuel_pct = metrics.get('fuel_cost_pct', 0.25)
        hedge_cov = metrics.get('hedge_coverage', 0.50)
        # Unhedged portion bears the full shock
        unhedged_exposure = fuel_pct * (1 - hedge_cov)
        margin_impact_pp = unhedged_exposure * oil_shock * 100
        results[ticker] = {
            'fuel_cost_pct': fuel_pct,
            'hedge_coverage': hedge_cov,
            'unhedged_exposure': round(unhedged_exposure * 100, 2),
            'margin_shrinkage_pp': round(margin_impact_pp, 2)
        }
    return results

